DELETE FROM ACCOUNT_STATUS_HISTORY   WHERE history_id IS NOT NULL;
DELETE FROM ACCOUNT                  WHERE account_number IS NOT NULL;
DELETE FROM ACCOUNT_APPLICATION      WHERE id IS NOT NULL;

